using System.Text.Json.Serialization;
using Newtonsoft.Json;

namespace RepairPlanner.Models;

/// <summary>
/// Output model: represents a complete work order generated by the Repair Planner Agent.
/// Saved to Cosmos DB WorkOrders container (partition key: status).
/// </summary>
public sealed class WorkOrder
{
    /// <summary>
    /// Unique identifier for the work order (partition key: status).
    /// </summary>
    [JsonPropertyName("id")]
    [JsonProperty("id")]
    public string Id { get; set; } = string.Empty;

    /// <summary>
    /// Human-readable work order number (e.g., "WO-2025-001234").
    /// </summary>
    [JsonPropertyName("workOrderNumber")]
    [JsonProperty("workOrderNumber")]
    public string WorkOrderNumber { get; set; } = string.Empty;

    /// <summary>
    /// ID of the machine that needs repair.
    /// </summary>
    [JsonPropertyName("machineId")]
    [JsonProperty("machineId")]
    public string MachineId { get; set; } = string.Empty;

    /// <summary>
    /// Brief title summarizing the repair work.
    /// </summary>
    [JsonPropertyName("title")]
    [JsonProperty("title")]
    public string Title { get; set; } = string.Empty;

    /// <summary>
    /// Detailed description of the work to be performed.
    /// </summary>
    [JsonPropertyName("description")]
    [JsonProperty("description")]
    public string Description { get; set; } = string.Empty;

    /// <summary>
    /// Type of repair: "corrective" (fix broken), "preventive" (avoid future issues), "emergency" (urgent fix).
    /// </summary>
    [JsonPropertyName("type")]
    [JsonProperty("type")]
    public string Type { get; set; } = "corrective";

    /// <summary>
    /// Priority level: "critical", "high", "medium", "low".
    /// </summary>
    [JsonPropertyName("priority")]
    [JsonProperty("priority")]
    public string Priority { get; set; } = "medium";

    /// <summary>
    /// Current status: "draft", "scheduled", "in_progress", "completed", "cancelled".
    /// Used as partition key in Cosmos DB.
    /// </summary>
    [JsonPropertyName("status")]
    [JsonProperty("status")]
    public string Status { get; set; } = "draft";

    /// <summary>
    /// ID of the technician assigned to perform the repair (or null if unassigned).
    /// </summary>
    [JsonPropertyName("assignedTo")]
    [JsonProperty("assignedTo")]
    public string? AssignedTo { get; set; }

    /// <summary>
    /// Name of the assigned technician (for reference).
    /// </summary>
    [JsonPropertyName("assignedTechnicianName")]
    [JsonProperty("assignedTechnicianName")]
    public string? AssignedTechnicianName { get; set; }

    /// <summary>
    /// Total estimated duration of the work order in minutes (sum of all task durations).
    /// Must be an integer (e.g., 120, not "120 minutes").
    /// </summary>
    [JsonPropertyName("estimatedDuration")]
    [JsonProperty("estimatedDuration")]
    public int EstimatedDuration { get; set; }

    /// <summary>
    /// Timestamp when the work order was created.
    /// </summary>
    [JsonPropertyName("createdAt")]
    [JsonProperty("createdAt")]
    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;

    /// <summary>
    /// Scheduled start time for the repair (null if not yet scheduled).
    /// </summary>
    [JsonPropertyName("scheduledStartTime")]
    [JsonProperty("scheduledStartTime")]
    public DateTime? ScheduledStartTime { get; set; }

    /// <summary>
    /// Actual completion timestamp (null if not completed).
    /// </summary>
    [JsonPropertyName("completedAt")]
    [JsonProperty("completedAt")]
    public DateTime? CompletedAt { get; set; }

    /// <summary>
    /// List of repair tasks that make up this work order, in execution order.
    /// </summary>
    [JsonPropertyName("tasks")]
    [JsonProperty("tasks")]
    public List<RepairTask> Tasks { get; set; } = new();

    /// <summary>
    /// List of parts needed for this work order.
    /// </summary>
    [JsonPropertyName("partsUsed")]
    [JsonProperty("partsUsed")]
    public List<WorkOrderPartUsage> PartsUsed { get; set; } = new();

    /// <summary>
    /// Total estimated cost of parts (sum of all part line items).
    /// </summary>
    [JsonPropertyName("estimatedPartsCost")]
    [JsonProperty("estimatedPartsCost")]
    public decimal EstimatedPartsCost => PartsUsed.Sum(p => p.TotalCost);

    /// <summary>
    /// Additional notes or comments about this work order.
    /// </summary>
    [JsonPropertyName("notes")]
    [JsonProperty("notes")]
    public string? Notes { get; set; }

    /// <summary>
    /// Reference to the fault that triggered this work order.
    /// </summary>
    [JsonPropertyName("relatedFaultId")]
    [JsonProperty("relatedFaultId")]
    public string? RelatedFaultId { get; set; }
}
